            f = f.reciprocal();
            fail("expecting ArithmeticException");
        } catch (ArithmeticException ex) {
        }


        f = new BigFraction(Integer.MAX_VALUE, 1);
        f = f.reciprocal();
        assertEquals(1, f.getNumeratorAsInt());
        assertEquals(Integer.MAX_VALUE, f.getDenominatorAsInt());
    }

