    public void testNegate() {
        Fraction f = null;

        f = new Fraction(50, 75);
        f = f.negate();
        assertEquals(-2, f.getNumerator());
        assertEquals(3, f.getDenominator());

        f = new Fraction(-50, 75);
        f = f.negate();
        assertEquals(2, f.getNumerator());
