        } catch (CardanEulerSingularityException cese) {

        } catch (Exception e) {
          fail("wrong exception caught: " + e.getMessage());
        }
      }
    }

    RotationOrder[] EulerOrders = {
            RotationOrder.XYX, RotationOrder.XZX, RotationOrder.YXY,
